using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences in the summary. Defaults to 3.
    /// </summary>
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

namespace DocSummary.Services;

public interface IDocumentSummaryService
{
    string Summarize(string documentText, int maxSentences);
}

namespace DocSummary.Services;

/// <summary>
/// Extractive summarization service that scores sentences by word frequency
/// and returns the top-ranked sentences in their original order.
/// </summary>
public class DocumentSummaryService : IDocumentSummaryService
{
    private static readonly char[] SentenceDelimiters = ['.', '!', '?'];

    public string Summarize(string documentText, int maxSentences)
    {
        if (string.IsNullOrWhiteSpace(documentText))
            return string.Empty;

        var sentences = SplitIntoSentences(documentText);

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var scoredSentences = ScoreSentences(sentences, wordFrequencies);

        // Take top N sentences by score, then reorder by original position
        var topSentences = scoredSentences
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .OrderBy(s => s.Index)
            .Select(s => s.Sentence);

        return string.Join(" ", topSentences);
    }

    private static List<string> SplitIntoSentences(string text)
    {
        var sentences = new List<string>();
        var start = 0;

        for (int i = 0; i < text.Length; i++)
        {
            if (SentenceDelimiters.Contains(text[i]))
            {
                var sentence = text[start..(i + 1)].Trim();
                if (sentence.Length > 0)
                    sentences.Add(sentence);
                start = i + 1;
            }
        }

        // Handle trailing text without a sentence delimiter
        if (start < text.Length)
        {
            var trailing = text[start..].Trim();
            if (trailing.Length > 0)
                sentences.Add(trailing);
        }

        return sentences;
    }

    private static Dictionary<string, int> ComputeWordFrequencies(List<string> sentences)
    {
        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in GetWords(sentence))
            {
                if (word.Length <= 2) continue; // skip short/common words
                frequencies[word] = frequencies.GetValueOrDefault(word) + 1;
            }
        }

        return frequencies;
    }

    private static List<(string Sentence, int Index, double Score)> ScoreSentences(
        List<string> sentences, Dictionary<string, int> wordFrequencies)
    {
        var scored = new List<(string Sentence, int Index, double Score)>();

        for (int i = 0; i < sentences.Count; i++)
        {
            var words = GetWords(sentences[i]);
            double score = words
                .Where(w => w.Length > 2)
                .Sum(w => wordFrequencies.GetValueOrDefault(w));

            // Normalize by word count to avoid bias toward long sentences
            if (words.Length > 0)
                score /= words.Length;

            scored.Add((sentences[i], i, score));
        }

        return scored;
    }

    private static string[] GetWords(string sentence)
    {
        return sentence.Split([' ', '\t', '\n', '\r', ',', ';', ':', '"', '(', ')', '[', ']'],
            StringSplitOptions.RemoveEmptyEntries);
    }
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController : ControllerBase
{
    private readonly IDocumentSummaryService _summaryService;

    public SummaryController(IDocumentSummaryService summaryService)
    {
        _summaryService = summaryService;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        if (!ModelState.IsValid)
            return BadRequest(ModelState);

        var summary = _summaryService.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

